document.addEventListener("DOMContentLoaded",function(){var e=document.querySelector(".hero__video"),t=document.querySelector(".hero__play-btn");e&&t&&t.addEventListener("click",function(){e.paused?(e.play(),t.classList.remove("is-paused")):(e.pause(),t.classList.add("is-paused"))})}),document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".hero__content .js-animate").forEach(function(e){e.classList.add("is-visible")})});